import csv
import os
from datetime import datetime

import modal

app = modal.App("etl-pipeline-orchestrator")

volume = modal.Volume.from_name("etl-pipeline-orchestrator-vol", create_if_missing=True)
secret = modal.Secret.from_name("etl-pipeline-orchestrator-secret")
output_dict = modal.Dict.from_name("etl-pipeline-orchestrator-output", create_if_missing=True)

OUTPUT_PATH = "/data/output.csv"


@app.cls(volumes={"/data": volume}, secrets=[secret])
class ETLPipeline:
    @modal.enter()
    def initialize(self) -> None:
        self.records_extracted = 0
        self.records_loaded = 0
        self.pipeline_status = "initialized"

    def extract(self) -> list[dict[str, str]]:
        api_token = os.environ.get("API_TOKEN", "")
        db_url = os.environ.get("DB_URL", "")
        if not api_token or not db_url:
            raise RuntimeError("Missing API_TOKEN or DB_URL in secrets")

        self.pipeline_status = "extracting"
        data = [
            {"id": "1", "name": "alpha", "timestamp": datetime.utcnow().isoformat()},
            {"id": "2", "name": "beta", "timestamp": datetime.utcnow().isoformat()},
            {"id": "3", "name": "gamma", "timestamp": datetime.utcnow().isoformat()},
        ]
        self.records_extracted = len(data)
        return data

    def transform(self, data: list[dict[str, str]]) -> list[dict[str, str]]:
        self.pipeline_status = "transforming"
        transformed = []
        for record in data:
            transformed.append(
                {
                    "id": record["id"],
                    "name": record["name"].upper(),
                    "timestamp": record["timestamp"],
                }
            )
        return transformed

    def load(self, data: list[dict[str, str]]) -> None:
        self.pipeline_status = "loading"
        with open(OUTPUT_PATH, "w", newline="") as output_file:
            writer = csv.DictWriter(output_file, fieldnames=["id", "name", "timestamp"])
            writer.writeheader()
            writer.writerows(data)

        self.records_loaded = len(data)
        volume.commit()

    @modal.method()
    def run(self) -> dict[str, str | int]:
        data = self.extract()
        transformed = self.transform(data)
        self.load(transformed)
        self.pipeline_status = "completed"
        return {
            "records_extracted": self.records_extracted,
            "records_loaded": self.records_loaded,
            "pipeline_status": self.pipeline_status,
            "output_path": OUTPUT_PATH,
        }


@app.function(schedule=modal.Period(hours=1), volumes={"/data": volume}, secrets=[secret])
def scheduled_pipeline() -> dict[str, str | int]:
    pipeline = ETLPipeline()
    return pipeline.run.remote()


@app.local_entrypoint()
def main() -> None:
    result = ETLPipeline().run.remote()
    output_dict["records_extracted"] = result["records_extracted"]
    output_dict["records_loaded"] = result["records_loaded"]
    output_dict["pipeline_status"] = result["pipeline_status"]
    output_dict["output_path"] = result["output_path"]
